    consumer.consume_serializer_zstd_compressor_level(config.serializer_zstd_compressor_level.clone());
    consumer.consume_site(config.site.clone());
    consumer.consume_skip_ssl_validation(config.skip_ssl_validation.clone());
    consumer.consume_sslkeylogfile(config.sslkeylogfile.clone());
    consumer.consume_statsd_forward_host(config.statsd_forward_host.clone());
